args.sparql:
SELECT ?athlete ?athleteLabel WHERE {
  ?athlete p:P2007 ?statement .
  ?statement ps:P2007 wd:Q47295100 .
  ?athlete rdfs:label ?athleteLabel .
  FILTER (LANG(?athleteLabel) = "en")
}

SELECT ?athlete ?athleteLabel
WHERE {
  wd:Q47295100 wdt:P2007 ?athlete .
  ?athlete rdfs:label ?athleteLabel .
  FILTER (LANG(?athleteLabel) = "en")
}

SELECT ?athlete ?athleteLabel ?medalTypeLabel
WHERE {
  ?athlete wdt:P166 ?medal.
  ?medal wdt:P2250 wd:Q47295100.
  ?medal pq:P253 ?medalType.
  ?athlete rdfs:label ?athleteLabel.
  FILTER(LANG(?athleteLabel) = "en");
  ?medalType rdfs:label ?medalTypeLabel.
  FILTER(LANG(?medalTypeLabel) = "en");
}
